1	/**
2	 * JigProcessManager — production ProcessManager implementation.
3	 *
4	 * Spawns whatever command + args the caller passes via SpawnOpts. There are
5	 * no 'claude' or 'jig' string constants anywhere in this file; the command
6	 * comes exclusively from ResolvedConfig via the caller.
7	 *
8	 * Process lifecycle:
9	 *   spawn(opts)
10	 *     → nodeSpawn(command, args, { detached:true })
11	 *     → register stdin 'error' handler (EPIPE named failure class)
12	 *     → child.stdin.end(promptBuffer)   ← one-shot; EPIPE caught above
13	 *     → readline stdout → emit 'stdout_line' per NDJSON line
14	 *     → stderr 'data' → cap at 64 KB, emit 'stderr_data' chunks
15	 *     → child 'exit' → emit 'exit'
16	 *     → cancel(): SIGTERM(-pgid) → gracePeriodMs → SIGKILL(-pgid)
17	 *
18	 * Zombie reap: detached:true + child.unref() — the child runs in its own
19	 * process group; unref() lets Node.js exit without waiting for it. The OS
20	 * (init/launchd) adopts and reaps the child if Yoke exits first.
21	 */
22	
23	import { spawn as nodeSpawn, type ChildProcess } from 'node:child_process';
24	import { EventEmitter } from 'node:events';
25	import { createInterface } from 'node:readline';
26	import { type SessionLogWriter } from '../session-log/writer.js';
27	import { ProcessError, type ProcessManager, type SpawnHandle, type SpawnOpts } from './manager.js';
28	
29	/** Maximum stderr bytes buffered before the cap is enforced. */
30	const STDERR_CAP_BYTES = 64 * 1024; // 64 KB
31	
32	// ---------------------------------------------------------------------------
33	// JigSpawnHandle (internal — not exported; callers program to SpawnHandle)
34	// ---------------------------------------------------------------------------
35	
36	class JigSpawnHandle extends EventEmitter implements SpawnHandle {
37	  readonly pid: number;
38	  /**
39	   * pgid === pid: with detached:true the child becomes its own process group
40	   * leader on POSIX. kill(-pgid, sig) delivers sig to every process in the
41	   * group (child + any sub-children it spawns).
42	   */
43	  readonly pgid: number;
44	
45	  private readonly child: ChildProcess;
46	  private readonly gracePeriodMs: number;
47	  private cancelTimer: ReturnType<typeof setTimeout> | null = null;
48	  private readonly logWriter: SessionLogWriter | null;
49	  /**
50	   * Promise chain ensuring sequential log writes — lines are appended in the
51	   * same order they arrive on stdout even though writeLine() is async.
52	   * The chain is also used to drain pending writes + close the writer before
53	   * the 'exit' event fires (guaranteeing log completeness for callers).
54	   */
55	  private _logChain: Promise<void> = Promise.resolve();
56	
57	  constructor(child: ChildProcess, gracePeriodMs: number, logWriter: SessionLogWriter | null) {
58	    super();
59	    this.child = child;
60	    this.pid = child.pid!;
61	    this.pgid = child.pid!;
62	    this.gracePeriodMs = gracePeriodMs;
63	    this.logWriter = logWriter;
64	
65	    this._wireStdin();
66	    this._wireStdout();
67	    this._wireStderr();
68	    this._wireExit();
69	  }
70	
71	  // -------------------------------------------------------------------------
72	  // Stream wiring
73	  // -------------------------------------------------------------------------
74	
75	  /**
76	   * Register the stdin 'error' handler BEFORE any write is scheduled.
77	   * Called synchronously from the constructor so the handler is in place
78	   * before child.stdin.end() runs on the next event-loop tick.
79	   */
80	  private _wireStdin(): void {
81	    this.child.stdin!.on('error', (err: NodeJS.ErrnoException) => {
82	      if (err.code === 'EPIPE') {
83	        // EPIPE is the named failure class for "child closed its stdin end
84	        // before we finished writing the prompt buffer."  This does NOT crash
85	        // the harness; it is caught here, logged via the 'error' event, and
86	        // the session continues to its natural exit.
87	        const pe = new ProcessError(
88	          'epipe',
89	          err,
90	          'EPIPE on stdin write: child closed the pipe before the prompt buffer was fully delivered',
91	        );
92	        this.emit('error', pe);
93	      } else {
94	        // Any other stdin I/O error (e.g. EBADF) — re-raise as a typed
95	        // ProcessError so no error is swallowed.
96	        this.emit('error', new ProcessError('stdin_error', err, `Unexpected stdin error: ${err.message}`));
97	      }
98	    });
99	  }
100	
101	  /**
102	   * Append one stdout line to the session log (verbatim stream-json line
103	   * copy, AC-1). Writes are chained so they are serialized — the log
104	   * preserves stdout line order regardless of I/O scheduling.
105	   * Write errors are suppressed (log is non-critical; session continues).
106	   */
107	  private _logLine(line: string): void {
108	    if (!this.logWriter) return;
109	    const writer = this.logWriter;
110	    this._logChain = this._logChain.then(() => writer.writeLine(line)).catch(() => {});
111	  }
112	
113	  /**
114	   * Line-buffered stdout reader (readline handles the trailing partial-line
115	   * buffer). Each complete line is emitted as 'stdout_line' for the
116	   * stream-json parser (process/stream-json.ts) to consume, and also
117	   * copied verbatim to the session log writer if one is set (AC-1).
118	   */
119	  private _wireStdout(): void {
120	    const rl = createInterface({ input: this.child.stdout!, crlfDelay: Infinity });
121	    rl.on('line', (line: string) => {
122	      this.emit('stdout_line', line);
123	      this._logLine(line);
124	    });
125	  }
126	
127	  /**
128	   * Stderr cap enforced in the stream 'data' handler — not by accumulating
