27	
28	export type RetryMode =
29	  | 'continue'
30	  | 'fresh_with_failure_summary'
31	  | 'fresh_with_diff'
32	  | 'awaiting_user';
33	
34	export type ActionValue =
35	  | 'continue'
36	  | 'stop-and-ask'
37	  | 'stop'
38	  | { goto: string; max_revisits?: number }
39	  | { retry: { mode: 'continue' | 'fresh_with_failure_summary' | 'fresh_with_diff'; max: number } }
40	  | { fail: { reason: string } };
41	
42	/** Keys are exit-code strings ("0"–"255") or the wildcard "*". */
